import { advancedPool, cpus } from '@danielsimonjr/workerpool';

this.workerPool = advancedPool(this.workerPath, {
  maxWorkers: cpus - 1,
  workerType: 'thread',
  workerChoiceStrategy: 'least-busy',
  enableWorkStealing: true
});

import { TaskAffinityRouter, createAffinityKey } from '@danielsimonjr/workerpool';

// Create affinity router
const affinityRouter = new TaskAffinityRouter(this.workerPool);

// Route similar queries to same worker
const affinityKey = createAffinityKey(query.substring(0, 3).toLowerCase());
await affinityRouter.execWithAffinity(affinityKey, 'searchEntities', [data]);
